#include <stdio.h>
#include <stdlib.h>

int main() {
    // CREATE and OPEN file for writing
    FILE *fp = fopen("data.txt", "w");
    if (fp == NULL) {
        printf("Error creating file\n");
        return 1;
    }

    // WRITE operation
    fprintf(fp, "Hello, File System!");
    fclose(fp);  // CLOSE operation

    // OPEN for reading
    fp = fopen("data.txt", "r");
    char buffer[100];

    // READ operation
    fgets(buffer, 100, fp);
    printf("Read: %s\n", buffer);
    fclose(fp);

    // Demonstrate SEEK (random access)
    fp = fopen("data.txt", "r+");
    fseek(fp, 0, SEEK_END);  // Move to end
    long size = ftell(fp);   // Get position (file size)
    printf("File size: %ld\n", size);
    fseek(fp, 0, SEEK_SET);  // Move to beginning
    fclose(fp);

    return 0;
}

import java.io.*;

public class FileDemo {
    public static void main(String[] args) throws IOException {
        // CREATE and WRITE using FileWriter
        FileWriter fw = new FileWriter("output.txt");
        fw.write("Line 1: Hello World\n");
        fw.write("Line 2: File Systems\n");
        fw.close();  // CLOSE operation

        // READ using FileReader
        FileReader fr = new FileReader("output.txt");
        int ch;
        while ((ch = fr.read()) != -1) {  // EOF check
            System.out.print((char) ch);
        }
        fr.close();

        // Direct access using RandomAccessFile
        RandomAccessFile raf = new RandomAccessFile("output.txt", "rw");

        // SEEK to beginning and read
        raf.seek(0);
        String line1 = raf.readLine();
        System.out.println("First line: " + line1);

        // SEEK to specific byte position
        raf.seek(7);  // Direct access to position 7
        System.out.println("Char at pos 7: " + (char)raf.readByte());

        // APPEND using seek to end
        raf.seek(raf.length());
        raf.writeBytes("Line 3: Appended data\n");

        raf.close();
    }
}
